// TC15: input { area:200, depth:3, soilType:"Potting_Mix", deliveryNeeded:false } → output { total: 101.85, breakdown: ... }
// TC16: input { area:100, depth:4, deliveryNeeded:false } → output { error: "Soil type is required" }
// TC17: input { depth:4, soilType:"topsoil", deliveryNeeded:false } → output { error: "Area is required" }
// TC18: input { area:1000, depth:2, soilType:"compost", deliveryNeeded:true } → output { total: 327.78, breakdown: ... }
// TC19: input { area:100, depth:4, soilType:"  topsoil  ", deliveryNeeded:false } → output normalizes, total: 37.04
// TC20: input { area:NaN, depth:4, soilType:"topsoil", deliveryNeeded:false } → output { error: "Area must be a positive number" }

const calculator = {
  // Cost per cubic yard by soil type (lowercase keys)
  SOIL_COSTS: {
    topsoil: 30,
    compost: 45,
    potting_mix: 55
  },
  DELIVERY_FEE: 50,

  validate(inputs) {
    const errors = [];

    // Area validation
    const area = inputs.area;
    if (area === undefined || area === null || area === '' || (typeof area !== 'number' && typeof area !== 'string')) {
      errors.push('Area is required');
    } else {
      const numArea = Number(area);
      if (isNaN(numArea) || !isFinite(numArea)) {
        errors.push('Area must be a positive number');
      } else if (numArea <= 0) {
        errors.push('Area must be > 0');
      }
    }

    // Depth validation
    const depth = inputs.depth;
    if (depth === undefined || depth === null || depth === '' || (typeof depth !== 'number' && typeof depth !== 'string')) {
      errors.push('Depth is required');
    } else {
      const numDepth = Number(depth);
      if (isNaN(numDepth) || !isFinite(numDepth)) {
        errors.push('Depth must be a positive number');
      } else if (numDepth <= 0) {
        errors.push('Depth must be > 0');
      }
    }

    // Soil type validation (case‑insensitive)
    const rawSoil = inputs.soilType;
    if (!rawSoil || (typeof rawSoil !== 'string')) {
      errors.push('Soil type is required');
    } else {
      const soil = String(rawSoil).trim().toLowerCase();
      if (!(soil in this.SOIL_COSTS)) {
        errors.push('Invalid soil type');
      }
    }

    // Delivery option validation
    const delivery = inputs.deliveryNeeded;
    if (typeof delivery !== 'boolean') {
      errors.push('Delivery option must be true or false');
    }

    return errors.length === 0 ? null : errors[0]; // return first error for simplicity
  },

  calculate(inputs) {
    const error = this.validate(inputs);
    if (error) {
      return { error };
    }

    // Extract and normalize values
    const area = Number(inputs.area);
    const depth = Number(inputs.depth);
    const soilKey = String(inputs.soilType).trim().toLowerCase();
    const costPerCubicYard = this.SOIL_COSTS[soilKey];
    const deliveryNeeded = Boolean(inputs.deliveryNeeded);

    // Volumes
    const volumeCubicFeet = area * depth / 12;
    const cubicYards = volumeCubicFeet / 27;

    // Costs
    const soilCost = cubicYards * costPerCubicYard;
    const deliveryFee = deliveryNeeded ? this.DELIVERY_FEE : 0;
    const total = Math.round((soilCost + deliveryFee) * 100) / 100; // to 2 decimals

    return {
      total,
      breakdown: {
        volumeCubicFeet,
        cubicYards: parseFloat(cubicYards.toFixed(4)), // keep 4 decimals for clarity
        soilCost: parseFloat(soilCost.toFixed(4)),
        deliveryFee,
        total
      }
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  {
    name: 'area',
    label: 'Area (sq ft)',
    type: 'number',
    placeholder: 'e.g. 100'
  },
  {
    name: 'depth',
    label: 'Depth (inches)',
    type: 'number',
    placeholder: 'e.g. 4'
  },
  {
    name: 'soilType',
    label: 'Soil Type',
    type: 'select',
    options: [
      ['topsoil', '🌱 Topsoil'],
      ['compost', '♻️ Compost'],
      ['potting_mix', '🪴 Potting Mix']
    ]
  },
  {
    name: 'deliveryNeeded',
    label: 'Delivery needed?',
    type: 'checkbox'
  }
];

